UPDATE product SET name_en = 'First Aid/Emergency Kit', description_en = '<p>The First Aid/Emergency Kit (SKU: KIT-URG-001) is a meticulously designed set of medical equipment for rapid and effective intervention in medical emergencies. This kit is ideal for healthcare professionals, first responders, and medical environments requiring immediate access to reliable and high-quality first aid tools. Each component has been selected to ensure optimal performance while providing maximum safety for both the caregiver and the patient.</p>

