UPDATE product SET name_en = 'Macintosh Laryngoscope – Cullinan | Intubation', description_en = '<p>The Macintosh - Cullinan Laryngoscope for intubation is a high-precision medical device designed to meet the rigorous demands of healthcare professionals during orotracheal intubation procedures. Made from premium 304 stainless steel, this instrument ensures optimal biocompatibility and corrosion resistance, providing exceptional durability even after multiple uses.</p>
