UPDATE product SET name_en = 'Coloplast Alterna Free White 1-Piece Urostomy Pouch', description_en = '<div style="font-family: Arial, sans-serif; color: #333; max-width: 800px; margin: 0 auto;">
    <p style="font-size: 1.2em; line-height: 1.6;">
