UPDATE product SET name_en = 'Sterile Scalpel Blades Paramount (No. 11)', description_en = '<p>Sterile stainless steel scalpel blades Paramount No. 11. Designed for precise incision and maximum safety in the operating room.</p><p>This medical device is designed with high clinical quality materials. Key technical features: <strong>Material</strong>: Medical-grade Carbon Steel. <strong>Sterilization</strong>: Gamma Radiation (25 kGy). <strong>Handle Compatibility</strong>: Handles No. 3, 3L, 5, 7. <strong>Packaging</strong>: Box of 100 units (individual aluminum packaging). <strong>Clinical Use</strong>: General surgery, precision incisions. </p>' WHERE id = 10006;
UPDATE product SET name_en = 'Sterile Scalpel Blades Paramount (No. 15)', description_en = '<p>Sterile scalpel blades in stainless steel Paramount No. 15. Curved shape for delicate dissections.</p><p>This medical device is designed with high clinical quality materials. Main technical features: <strong>Material</strong>: Medical-grade Carbon Steel. <strong>Sterilization</strong>: Gamma Radiation (25 kGy). <strong>Handle Compatibility</strong>: Handles No. 3, 3L, 5, 7. <strong>Packaging</strong>: Box of 100 units (individually wrapped in aluminum). <strong>Clinical Use</strong>: Delicate dissections, dermatological surgery. </p>' WHERE id = 10007;
